mapper.select:
SELECT * FROM person_archives_data
WHERE person_id = #{personId}
  AND work_type = #{workType}
ORDER BY created_at DESC

SELECT d.id, d.config_id as configId, d.person_id as personId, d.user_id as userId, d.work_type as workType, d.org_id as orgId, d.project_id as projectId, d.team_name as teamName, d.archive_data as archiveData, d.generated_doc_url as generatedDocUrl, d.archive_number as archiveNumber, d.status, d.created_at as createdAt, d.updated_at as updatedAt, p.name as personName, s.color as safetyColor, s.status as safetyStatus FROM person_archives_data d LEFT JOIN xm_person p ON d.person_id = p.id LEFT JOIN safety_codes s ON p.user_id = s.user_id
d.is_delete = 0
AND d.config_id = #{configId}
AND d.person_id = #{personId}
AND d.archive_number LIKE CONCAT('%', #{archiveNumber}, '%')
ORDER BY d.created_at DESC
